package com.example.documentviewer;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.util.Log;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.Toast;
import androidx.annotation.Nullable;
import com.github.barteksc.pdfviewer.PDFView;
import java.io.FileNotFoundException;
import java.io.InputStream;

public class DocumentViewerActivity extends Activity {
    
    private static final String TAG = "DocumentViewerActivity";
    private static final String[] ALLOWED_SCHEMES = {"content", "file"};
    private static final String[] ALLOWED_MIME_TYPES = {
        "application/pdf",
        "image/jpeg",
        "image/jpg",
        "image/png",
        "image/gif",
        "image/bmp",
        "image/webp"
    };
    
    private PDFView pdfView;
    private ImageView imageView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);
        
        pdfView = findViewById(R.id.pdfView);
        imageView = findViewById(R.id.imageView);
        
        if (!handleIntent(getIntent())) {
            Toast.makeText(this, "Unable to open document", Toast.LENGTH_SHORT).show();
            finish();
        }
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        if (!handleIntent(intent)) {
            Toast.makeText(this, "Unable to open document", Toast.LENGTH_SHORT).show();
            finish();
        }
    }

    private boolean handleIntent(Intent intent) {
        if (intent == null) {
            Log.e(TAG, "Intent is null");
            return false;
        }

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            Log.e(TAG, "Invalid action: " + action);
            return false;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            Log.e(TAG, "URI is null");
            return false;
        }

        if (!isValidUri(uri)) {
            Log.e(TAG, "Invalid URI scheme: " + uri.getScheme());
            return false;
        }

        String mimeType = intent.getType();
        if (mimeType == null) {
            mimeType = getMimeTypeFromUri(uri);
        }

        if (!isAllowedMimeType(mimeType)) {
            Log.e(TAG, "Unsupported MIME type: " + mimeType);
            return false;
        }

        if (!validateUriAccess(uri)) {
            Log.e(TAG, "Cannot access URI: " + uri);
            return false;
        }

        return displayDocument(uri, mimeType);
    }

    private boolean isValidUri(Uri uri) {
        if (uri == null) {
            return false;
        }
        
        String scheme = uri.getScheme();
        if (scheme == null) {
            return false;
        }
        
        for (String allowedScheme : ALLOWED_SCHEMES) {
            if (allowedScheme.equalsIgnoreCase(scheme)) {
                return true;
            }
        }
        
        return false;
    }

    private boolean isAllowedMimeType(String mimeType) {
        if (mimeType == null) {
            return false;
        }
        
        String normalizedMimeType = mimeType.toLowerCase().trim();
        for (String allowedType : ALLOWED_MIME_TYPES) {
            if (allowedType.equals(normalizedMimeType)) {
                return true;
            }
        }
        
        return false;
    }

    private String getMimeTypeFromUri(Uri uri) {
        String mimeType = getContentResolver().getType(uri);
        
        if (mimeType == null) {
            String extension = MimeTypeMap.getFileExtensionFromUrl(uri.toString());
            if (extension != null) {
                mimeType = MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension.toLowerCase());
            }
        }
        
        return mimeType;
    }

    private boolean validateUriAccess(Uri uri) {
        try {
            InputStream inputStream = getContentResolver().openInputStream(uri);
            if (inputStream != null) {
                inputStream.close();
                return true;
            }
        } catch (FileNotFoundException e) {
            Log.e(TAG, "File not found: " + uri, e);
        } catch (SecurityException e) {
            Log.e(TAG, "Security exception accessing URI: " + uri, e);
        } catch (Exception e) {
            Log.e(TAG, "Error accessing URI: " + uri, e);
        }
        return false;
    }

    private boolean displayDocument(Uri uri, String mimeType) {
        try {
            if (mimeType.equals("application/pdf")) {
                return displayPdf(uri);
            } else if (mimeType.startsWith("image/")) {
                return displayImage(uri);
            }
        } catch (SecurityException e) {
            Log.e(TAG, "Security exception displaying document", e);
            Toast.makeText(this, "Permission denied", Toast.LENGTH_SHORT).show();
        } catch (Exception e) {
            Log.e(TAG, "Error displaying document", e);
            Toast.makeText(this, "Error opening document", Toast.LENGTH_SHORT).show();
        }
        return false;
    }

    private boolean displayPdf(Uri uri) {
        try {
            pdfView.setVisibility(android.view.View.VISIBLE);
            imageView.setVisibility(android.view.View.GONE);
            
            pdfView.fromUri(uri)
                .enableSwipe(true)
                .swipeHorizontal(false)
                .enableDoubletap(true)
                .defaultPage(0)
                .enableAnnotationRendering(false)
                .password(null)
                .scrollHandle(null)
                .enableAntialiasing(true)
                .spacing(0)
                .load();
            
            return true;
        } catch (Exception e) {
            Log.e(TAG, "Error loading PDF", e);
            return false;
        }
    }

    private boolean displayImage(Uri uri) {
        try {
            pdfView.setVisibility(android.view.View.GONE);
            imageView.setVisibility(android.view.View.VISIBLE);
            
            imageView.setImageURI(uri);
            return true;
        } catch (Exception e) {
            Log.e(TAG, "Error loading image", e);
            return false;
        }
    }
}